// 环形缓冲区实现 - 静态分配的经典应用

template&lt;typename T, size_t N&gt;
class RingBuffer {
    static_assert(N &gt; 0 &amp;&amp; (N &amp; (N - 1)) == 0,
                  "Size must be power of 2 for efficient masking");

    std::array&lt;T, N&gt; buffer_;
    size_t head_ = 0;
    size_t tail_ = 0;
    size_t mask_ = N - 1;

public:
    RingBuffer() = default;

    // 非阻塞push
    bool push(const T&amp; value) {
        size_t next = (head_ + 1) &amp; mask_;
        if (next == tail_) {
            return false;  // Full
        }
        buffer_[head_] = value;
        head_ = next;
        return true;
    }

    // 非阻塞pop
    bool pop(T&amp; out) {
        if (head_ == tail_) {
            return false;  // Empty
        }
        out = buffer_[tail_];
        tail_ = (tail_ + 1) &amp; mask_;
        return true;
    }

    bool empty() const { return head_ == tail_; }
    bool full() const { return ((head_ + 1) &amp; mask_) == tail_; }
    size_t size() const { return (head_ - tail_) &amp; mask_; }
    size_t capacity() const { return N - 1; }

    void clear() { head_ = tail_ = 0; }
};

// 字节型环形缓冲区
template&lt;size_t N&gt;
class ByteRingBuffer {
    std::array&lt;uint8_t, N&gt; buffer_;
    size_t head_ = 0;
    size_t tail_ = 0;

public:
    // 写入数据
    size_t write(const uint8_t* data, size_t len) {
        size_t written = 0;
        for (size_t i = 0; i &lt; len; ++i) {
            size_t next = (head_ + 1) % N;
            if (next == tail_) break;  // Full
            buffer_[head_] = data[i];
            head_ = next;
            ++written;
        }
        return written;
    }

    // 读取数据
    size_t read(uint8_t* data, size_t len) {
        size_t read_count = 0;
        for (size_t i = 0; i &lt; len; ++i) {
            if (head_ == tail_) break;  // Empty
            data[i] = buffer_[tail_];
            tail_ = (tail_ + 1) % N;
            ++read_count;
        }
        return read_count;
    }

    size_t size() const {
        if (head_ &gt;= tail_) return head_ - tail_;
        return N - tail_ + head_;
    }

    size_t available() const { return N - size() - 1; }
    bool empty() const { return head_ == tail_; }
    bool full() const { return ((head_ + 1) % N) == tail_; }
};

