    std::cout &lt;&lt; "\n--- Using packets ---\n";
    p1-&gt;init();
    p1-&gt;append("Hello, ", 7);
    p1-&gt;append("World!", 6);
    p1-&gt;print();

    p2-&gt;init();
    p2-&gt;append("Packet 2", 8);
    p2-&gt;print();

    std::cout &lt;&lt; "\n--- Releasing packets ---\n";
    pktPool.release(p1);
    std::cout &lt;&lt; "After releasing p1, free slots: " &lt;&lt; pktPool.free_count() &lt;&lt; "\n";

    pktPool.release(p2);
