    std::cout &lt;&lt; "3. Use alignas() or aligned_storage for proper alignment\n";
    std::cout &lt;&lt; "4. Exception safety requires manual cleanup in catch blocks\n";
    std::cout &lt;&lt; "5. Never use delete on placement-new objects\n";

