    std::cout &lt;&lt; "Initial available: " &lt;&lt; arena.available() &lt;&lt; " bytes\n\n";

    // 分配对象
    std::cout &lt;&lt; "--- Allocating objects ---\n";
    void* p1 = arena.allocate(sizeof(Widget), alignof(Widget));
    if (p1) {
        Widget* w1 = new (p1) Widget(1, "First", 3.14);
