    std::cout &lt;&lt; "\nUsed: " &lt;&lt; arena.used() &lt;&lt; " bytes\n";
    std::cout &lt;&lt; "Available: " &lt;&lt; arena.available() &lt;&lt; " bytes\n";

    // 手动析构
    std::cout &lt;&lt; "\n--- Manual destruction ---\n";
    if (p1) {
        static_cast&lt;Widget*&gt;(p1)-&gt;~Widget();
