template&lt;typename T&gt;
class Optional {
    alignas(T) unsigned char storage_[sizeof(T)];
    bool has_value_ = false;

public:
    Optional() noexcept = default;

    ~Optional() {
        reset();
    }

    Optional(const Optional&amp; other) {
        if (other.has_value_) {
            new (storage_) T(*reinterpret_cast&lt;const T*&gt;(other.storage_));
            has_value_ = true;
        }
    }

    Optional(Optional&amp;&amp; other) noexcept {
        if (other.has_value_) {
            new (storage_) T(std::move(*reinterpret_cast&lt;T*&gt;(other.storage_)));
            has_value_ = true;
            other.reset();
        }
    }

    template&lt;typename U&gt;
    Optional(U&amp;&amp; value) {
        new (storage_) T(std::forward&lt;U&gt;(value));
        has_value_ = true;
    }

    Optional&amp; operator=(const Optional&amp; other) {
        if (this != &amp;other) {
            reset();
            if (other.has_value_) {
                new (storage_) T(*reinterpret_cast&lt;const T*&gt;(other.storage_));
                has_value_ = true;
            }
        }
        return *this;
    }

    Optional&amp; operator=(Optional&amp;&amp; other) noexcept {
        if (this != &amp;other) {
            reset();
            if (other.has_value_) {
                new (storage_) T(std::move(*reinterpret_cast&lt;T*&gt;(other.storage_)));
                has_value_ = true;
                other.reset();
            }
        }
        return *this;
    }

    void reset() {
        if (has_value_) {
            reinterpret_cast&lt;T*&gt;(storage_)-&gt;~T();
            has_value_ = false;
        }
    }

    template&lt;typename U&gt;
    void emplace(U&amp;&amp; args) {
        reset();
        new (storage_) T(std::forward&lt;U&gt;(args));
        has_value_ = true;
    }

    T&amp; operator*() { return *reinterpret_cast&lt;T*&gt;(storage_); }
    const T&amp; operator*() const { return *reinterpret_cast&lt;const T*&gt;(storage_); }

    T* operator-&gt;() { return reinterpret_cast&lt;T*&gt;(storage_); }
    const T* operator-&gt;() const { return reinterpret_cast&lt;const T*&gt;(storage_); }

    explicit operator bool() const { return has_value_; }
    bool has_value() const { return has_value_; }
};

