    int val;
    while (rb.pop(val)) {
        std::cout &lt;&lt; "  " &lt;&lt; val &lt;&lt; "\n";
    }

    std::cout &lt;&lt; "Buffer empty: " &lt;&lt; (rb.empty() ? "yes" : "no") &lt;&lt; "\n";
}

