// 示例6：传感器数据缓冲
struct SensorData {
    uint32_t timestamp;
    float value;
    uint8_t status;
};

class SensorBuffer {
    std::array&lt;SensorData, 100&gt; buffer_;
    size_t count_ = 0;

public:
    bool add(const SensorData&amp; data) {
        if (count_ &gt;= buffer_.size()) {
            return false;
        }
        buffer_[count_++] = data;
        return true;
    }

    const SensorData* get_latest() const {
        if (count_ == 0) return nullptr;
        return &amp;buffer_[count_ - 1];
    }

    const SensorData* get(size_t index) const {
        if (index &gt;= count_) return nullptr;
        return &amp;buffer_[index];
    }

    size_t count() const { return count_; }

    void clear() { count_ = 0; }

    // 统计
    float average() const {
        if (count_ == 0) return 0.0f;
        float sum = 0.0f;
        for (size_t i = 0; i &lt; count_; ++i) {
            sum += buffer_[i].value;
        }
        return sum / count_;
    }

    float min() const {
        if (count_ == 0) return 0.0f;
        float m = buffer_[0].value;
        for (size_t i = 1; i &lt; count_; ++i) {
            if (buffer_[i].value &lt; m) m = buffer_[i].value;
        }
        return m;
    }

    float max() const {
        if (count_ == 0) return 0.0f;
        float m = buffer_[0].value;
        for (size_t i = 1; i &lt; count_; ++i) {
            if (buffer_[i].value &gt; m) m = buffer_[i].value;
        }
        return m;
    }
};

